import { useState } from 'react';
import { IconCar, IconSearch, IconCart } from './Icons.jsx';

const VEHICLE_TYPES = [
  { id: 'car', label: 'Vehículo de turismo', href: 'https://www.autodoc.es/repuestos' },
  { id: 'truck', label: 'Camión', href: 'https://camiones.autodoc.es/' },
  { id: 'moto', label: 'Motocicleta', href: 'https://moto.autodoc.es/' },
];

export default function VehicleTypeBar() {
  const [open, setOpen] = useState(false);
  const [type, setType] = useState(VEHICLE_TYPES[0]);
  return (
    <div className="bg-header-bg text-header-text border-t border-white/10">
      <div className="max-w-[1430px] mx-auto px-5 h-[58px] flex items-center gap-6">
        {/* Vehicle type dropdown */}
        <div className="relative">
          <button
            onClick={() => setOpen((o) => !o)}
            className="flex items-center gap-2 h-9 px-3 bg-white/5 border border-white/10 rounded hover:bg-white/10"
          >
            <IconCar className="w-5 h-5" />
            <span className="text-[13px]">{type.label}</span>
            <span className="text-header-text/60 text-[10px]">▾</span>
          </button>
          {open && (
            <ul className="absolute top-full left-0 mt-1 bg-white text-body-text shadow-lg rounded min-w-[200px] z-50">
              {VEHICLE_TYPES.map((t) => (
                <li key={t.id}>
                  <button
                    onClick={() => { setType(t); setOpen(false); }}
                    className={`w-full text-left px-3 py-2 text-[13px] hover:bg-gray-100 ${t.id === type.id ? 'font-semibold' : ''}`}
                  >
                    {t.label}
                  </button>
                </li>
              ))}
            </ul>
          )}
        </div>
        {/* Free-text search */}
        <form
          onSubmit={(e) => e.preventDefault()}
          className="flex-1 max-w-[720px] flex items-center bg-white rounded h-10 px-3"
        >
          <input
            type="text"
            placeholder="Introduzca el número o el nombre de la pieza"
            className="flex-1 outline-none text-[13px] text-body-text placeholder:text-gray-muted bg-transparent"
          />
          <button type="submit" aria-label="Buscar" className="text-body-text hover:text-cta-blue">
            <IconSearch className="w-5 h-5" />
          </button>
        </form>
        {/* Cart summary */}
        <div className="ml-auto flex items-center gap-3">
          <IconCart className="w-7 h-7" />
          <div className="text-[12px] leading-tight">
            <div>Artículos <span className="ml-1">0,00 €</span></div>
            <div className="text-header-text/60">#26-9712</div>
          </div>
          <span className="text-header-text/60 text-[10px]">▾</span>
        </div>
      </div>
    </div>
  );
}
