            className="flex-1 h-12 px-3 outline-none text-[14px] text-body-text"
            style={{
              backgroundColor: '#FFFFFF',
              border: '1px solid #C4D0D8',
              borderLeft: 'none',
              borderRadius: '0',
              fontWeight: 500,
            }}
          />
          <button
            type="button"
            disabled={!canSearchPlate}
            onClick={() => canSearchPlate && alert(`Buscar por matrícula: ${plate}`)}
            className="h-12 px-6 text-white font-semibold text-[13px] tracking-wide transition-colors"
            style={{
              fontFamily: 'Montserrat, Arial, sans-serif',
