      rect: (function(){const r = carousel.getBoundingClientRect(); return { x:r.x|0, y:r.y|0, w:r.width|0, h:r.height|0 };})(),
    }, null, 2);
  })()`,

  // AC-10 hover (we'll run before + after hover via separate script)
