    function rgbToHexLocal(rgb) { const m=(rgb||'').match(/\\d+/g); if(!m)return rgb; return '#'+m.slice(0,3).map(n=>parseInt(n).toString(16).padStart(2,'0')).join('').toUpperCase(); }
