  // AC-11 orange/accent separators
  orangeAccents: `(() => {
    const oranges = Array.from(document.querySelectorAll('*'))
      .map(el => ({ el, bg: getComputedStyle(el).backgroundColor, color: getComputedStyle(el).color }))
