            value={plate}
            onChange={(e) => setPlate(e.target.value)}
            placeholder="1234-ABC"
            maxLength={12}
            aria-label="Matrícula"
            className="flex-1 outline-none text-[14px] text-body-text"
            style={{
              backgroundColor: '#FFFFFF',
              border: '1px solid #C4D0D8',
              borderLeft: 'none',
              borderRadius: '0',
